**Recommendation: Option A — Modify `computePQAverageScore()` to return a richer object.**

Rename it to `computePQScores()` and return:

```typescript
export interface PQDimensionScores {
  overall: number;
  context_provision: number;
  request_specificity: number;
  scope_management: number;
  information_timing: number;
  correction_quality: number;
}

export function computePQScores(
  db: ReturnType<typeof getDb>,
  where: string,
  params: (string | number)[]
